      numero: "22",
      caput: "As atividades de atenção e as de reinserção social do usuário e do dependente de drogas e respectivos familiares devem observar os seguintes princípios e diretrizes:",
      paragrafos: [],
      incisos: [{"id":"ld:art-22-inc-I","numero":"I","texto":"respeito ao usuário e ao dependente de drogas, independentemente de quaisquer condições, observados os direitos fundamentais da pessoa humana, os princípios e diretrizes do Sistema Único de Saúde e da Política Nacional de Assistência Social;","alineas":[]},{"id":"ld:art-22-inc-II","numero":"II","texto":"a adoção de estratégias diferenciadas de atenção e reinserção social do usuário e do dependente de drogas e respectivos familiares que considerem as suas peculiaridades socioculturais;","alineas":[]},{"id":"ld:art-22-inc-III","numero":"III","texto":"definição de projeto terapêutico individualizado, orientado para a inclusão social e para a redução de riscos e de danos sociais e à saúde;","alineas":[]},{"id":"ld:art-22-inc-IV","numero":"IV","texto":"atenção ao usuário ou dependente de drogas e aos respectivos familiares, sempre que possível, de forma multidisciplinar e por equipes multiprofissionais;","alineas":[]},{"id":"ld:art-22-inc-V","numero":"V","texto":"observância das orientações e normas emanadas do Conad;","alineas":[]},{"id":"ld:art-22-inc-VI","numero":"VI","texto":"o alinhamento às diretrizes dos órgãos de controle social de políticas setoriais específicas.","alineas":[]},{"id":"ld:art-22-inc-VII","numero":"VII","texto":"estímulo à capacitação técnica e profissional;","alineas":[]},{"id":"ld:art-22-inc-VIII","numero":"VIII","texto":"efetivação de políticas de reinserção social voltadas à educação continuada e ao trabalho;","alineas":[]},{"id":"ld:art-22-inc-IX","numero":"IX","texto":"observância do plano individual de atendimento na forma do art. 23-B desta Lei;","alineas":[]},{"id":"ld:art-22-inc-X","numero":"X","texto":"orientação adequada ao usuário ou dependente de drogas quanto às consequências lesivas do uso de drogas, ainda que ocasional.","alineas":[]}],
